import com.google.gson.annotations.SerializedName

data class WalletTransaction(
    @SerializedName("transaction_id") val transactionId: String,
    @SerializedName("amount") val amount: Double,
    @SerializedName("currency") val currency: String,
    @SerializedName("timestamp") val timestamp: Long,
    @SerializedName("type") val type: TransactionType,
    @SerializedName("status") val status: TransactionStatus,
    @SerializedName("description") val description: String,
    @SerializedName("card_last_four") val cardLastFour: String? = null
)

enum class TransactionType {
    DEPOSIT, WITHDRAWAL, PURCHASE, REFUND
}

enum class TransactionStatus {
    PENDING, COMPLETED, FAILED, CANCELLED
}

data class PaymentCard(
    @SerializedName("card_id") val cardId: String,
    @SerializedName("last_four") val lastFour: String,
    @SerializedName("card_type") val cardType: String,
    @SerializedName("expiry_month") val expiryMonth: Int,
    @SerializedName("expiry_year") val expiryYear: Int,
    @SerializedName("is_default") val isDefault: Boolean
)

data class WalletBalance(
    @SerializedName("balance") val balance: Double,
    @SerializedName("currency") val currency: String,
    @SerializedName("available_balance") val availableBalance: Double
)

data class PaymentRequest(
    @SerializedName("amount") val amount: Double,
    @SerializedName("currency") val currency: String,
    @SerializedName("payment_method") val paymentMethod: String,
    @SerializedName("description") val description: String,
    @SerializedName("user_id") val userId: String,
    @SerializedName("metadata") val metadata: Map<String, String>? = null
)

data class PaymentResponse(
    @SerializedName("success") val success: Boolean,
    @SerializedName("transaction_id") val transactionId: String?,
    @SerializedName("message") val message: String,
    @SerializedName("error_code") val errorCode: String?
)

data class InAppProduct(
    val productId: String,
    val name: String,
    val description: String,
    val price: String,
    val priceMicros: Long,
    val currency: String,
    val type: ProductType
)

enum class ProductType {
    CONSUMABLE, NON_CONSUMABLE, SUBSCRIPTION
}

sealed class PaymentResult {
    data class Success(val transaction: WalletTransaction) : PaymentResult()
    data class Error(val message: String, val code: String? = null) : PaymentResult()
