import retrofit2.Response
import retrofit2.http.*

interface PaymentApiService {
    
    @POST("wallet/deposit")
    suspend fun depositFunds(@Body request: PaymentRequest): Response<PaymentResponse>
    
    @POST("wallet/withdraw")
    suspend fun withdrawFunds(@Body request: PaymentRequest): Response<PaymentResponse>
    
    @GET("wallet/balance")
    suspend fun getWalletBalance(@Query("user_id") userId: String): Response<WalletBalance>
    
    @GET("wallet/transactions")
    suspend fun getTransactionHistory(
        @Query("user_id") userId: String,
        @Query("limit") limit: Int = 50
    ): Response<List<WalletTransaction>>
    
    @POST("payment/process")
