    @GET("payment/cards")
    suspend fun getPaymentCards(@Query("user_id") userId: String): Response<List<PaymentCard>>
    
    @POST("payment/cards")
    suspend fun addPaymentCard(@Body card: Map<String, String>): Response<PaymentResponse>
    
    @DELETE("payment/cards/{card_id}")
    suspend fun removePaymentCard(@Path("card_id") cardId: String): Response<PaymentResponse>
    
    @POST("payment/verify")
    suspend fun verifyPayment(
        @Body verification: Map<String, String>
    ): Response<PaymentResponse>
