// NetworkModule.kt
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {
    
    private fun createOkHttpClient(): OkHttpClient {
        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = HttpLoggingInterceptor.Level.BODY
        }
        
        return OkHttpClient.Builder()
            .addInterceptor(loggingInterceptor)
            .addInterceptor { chain ->
                val request = chain.request().newBuilder()
                    .addHeader("Content-Type", "application/json")
                    .addHeader("Accept", "application/json")
                    .build()
                chain.proceed(request)
            }
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .build()
    }
    
    fun provideRetrofit(): Retrofit {
        return Retrofit.Builder()
            .baseUrl(PaymentConfig.BASE_URL)
            .client(createOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
    
    fun providePaymentApiService(): PaymentApiService {
        return provideRetrofit().create(PaymentApiService::class.java)
    }
}

// InAppPurchaseManager.kt
import android.app.Activity
import android.content.Context
import com.android.billingclient.api.*
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.callbackFlow
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlin.coroutines.resume

class InAppPurchaseManager(
    private val context: Context,
    private val securityManager: SecurityManager
) {

    private var billingClient: BillingClient? = null
    private var purchasesUpdatedListener = PurchasesUpdatedListener { billingResult, purchases ->
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    handlePurchase(purchase)
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                // User cancelled
            }
            else -> {
                // Handle error
            }
        }
    }

    fun initialize(): Flow<Boolean> = callbackFlow {
        billingClient = BillingClient.newBuilder(context)
            .setListener(purchasesUpdatedListener)
            .enablePendingPurchases()
            .build()

        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    trySend(true)
                } else {
                    trySend(false)
                }
            }

            override fun onBillingServiceDisconnected() {
                trySend(false)
            }
        })

        awaitClose { disconnect() }
    }

    suspend fun queryProducts(productIds: List<String>, productType: String): List<InAppProduct> {
        return suspendCancellableCoroutine { continuation ->
            val productList = productIds.map { productId ->
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId(productId)
                    .setProductType(productType)
                    .build()
            }

            val params = QueryProductDetailsParams.newBuilder()
                .setProductList(productList)
                .build()

            billingClient?.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    val products = productDetailsList.map { productDetails ->
                        val pricing = productDetails.oneTimePurchaseOfferDetails
                        InAppProduct(
                            productId = productDetails.productId,
                            name = productDetails.name,
                            description = productDetails.description,
                            price = pricing?.formattedPrice ?: "",
                            priceMicros = pricing?.priceAmountMicros ?: 0L,
                            currency = pricing?.priceCurrencyCode ?: "",
                            type = if (productDetails.productType == BillingClient.ProductType.INAPP) 
                                ProductType.CONSUMABLE else ProductType.SUBSCRIPTION
                        )
                    }
                    continuation.resume(products)
                } else {
                    continuation.resume(emptyList())
                }
            }
        }
    }

    fun launchPurchaseFlow(activity: Activity, productDetails: ProductDetails) {
        val productDetailsParamsList = listOf(
            BillingFlowParams.ProductDetailsParams.newBuilder()
                .setProductDetails(productDetails)
                .build()
        )

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(productDetailsParamsList)
            .build()

        billingClient?.launchBillingFlow(activity, billingFlowParams)
    }

    private fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            if (!purchase.isAcknowledged) {
                acknowledgePurchase(purchase)
            }
            savePurchaseSecurely(purchase)
        }
    }

    private fun acknowledgePurchase(purchase: Purchase) {
        val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        billingClient?.acknowledgePurchase(acknowledgePurchaseParams) { billingResult ->
            // Handle acknowledgment result
        }
    }

    private fun savePurchaseSecurely(purchase: Purchase) {
        val purchaseData = "${purchase.orderId}:${purchase.purchaseToken}:${purchase.purchaseTime}"
        val encrypted = securityManager.encryptData(purchaseData)
        securityManager.saveEncryptedData("purchase_${purchase.orderId}", encrypted)
    }

    suspend fun consumePurchase(purchaseToken: String): Boolean {
        return suspendCancellableCoroutine { continuation ->
            val consumeParams = ConsumeParams.newBuilder()
                .setPurchaseToken(purchaseToken)
                .build()

            billingClient?.consumeAsync(consumeParams) { billingResult, _ ->
                continuation.resume(billingResult.responseCode == BillingClient.BillingResponseCode.OK)
            }
        }
    }

    fun disconnect() {
        billingClient?.endConnection()
        billingClient = null
    }
}

// WalletManager.kt
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.flow.flowOn
import kotlinx.coroutines.withContext

class WalletManager(
    private val apiService: PaymentApiService,
    private val securityManager: SecurityManager
) {

    suspend fun getBalance(userId: String): Flow<PaymentResult> = flow {
        emit(PaymentResult.Loading)
        try {
            val response = apiService.getWalletBalance(userId)
            if (response.isSuccessful && response.body() != null) {
                val balance = response.body()!!
                saveBalanceSecurely(balance)
                emit(PaymentResult.Success(
                    WalletTransaction(
                        transactionId = "",
                        amount = balance.balance,
                        currency = balance.currency,
                        timestamp = System.currentTimeMillis(),
                        type = TransactionType.DEPOSIT,
                        status = TransactionStatus.COMPLETED,
                        description = "Balance Check"
                    )
                ))
            } else {
                emit(PaymentResult.Error("Failed to fetch balance"))
            }
        } catch (e: Exception) {
            emit(PaymentResult.Error(e.message ?: "Unknown error"))
        }
    }.flowOn(Dispatchers.IO)

    suspend fun depositFunds(
        userId: String,
        amount: Double,
        currency: String,
        paymentMethod: String
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val request = PaymentRequest(
                    amount = amount,
                    currency = currency,
                    paymentMethod = paymentMethod,
                    description = "Wallet Deposit",
                    userId = userId
                )
                
                val response = apiService.depositFunds(request)
                if (response.isSuccessful && response.body()?.success == true) {
                    val transactionId = response.body()!!.transactionId ?: ""
                    val transaction = WalletTransaction(
                        transactionId = transactionId,
                        amount = amount,
                        currency = currency,
                        timestamp = System.currentTimeMillis(),
                        type = TransactionType.DEPOSIT,
                        status = TransactionStatus.COMPLETED,
                        description = "Wallet Deposit"
                    )
                    saveTransactionSecurely(transaction)
                    PaymentResult.Success(transaction)
                } else {
                    PaymentResult.Error(
                        response.body()?.message ?: "Deposit failed",
                        response.body()?.errorCode
                    )
                }
            } catch (e: Exception) {
                PaymentResult.Error(e.message ?: "Unknown error")
            }
        }
    }

    suspend fun withdrawFunds(
        userId: String,
        amount: Double,
        currency: String,
        paymentMethod: String
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val request = PaymentRequest(
                    amount = amount,
                    currency = currency,
                    paymentMethod = paymentMethod,
                    description = "Wallet Withdrawal",
                    userId = userId
                )
                
                val response = apiService.withdrawFunds(request)
                if (response.isSuccessful && response.body()?.success == true) {
                    val transactionId = response.body()!!.transactionId ?: ""
                    val transaction = WalletTransaction(
                        transactionId = transactionId,
                        amount = amount,
                        currency = currency,
                        timestamp = System.currentTimeMillis(),
                        type = TransactionType.WITHDRAWAL,
                        status = TransactionStatus.COMPLETED,
                        description = "Wallet Withdrawal"
                    )
                    saveTransactionSecurely(transaction)
                    PaymentResult.Success(transaction)
                } else {
                    PaymentResult.Error(
                        response.body()?.message ?: "Withdrawal failed",
                        response.body()?.errorCode
                    )
                }
            } catch (e: Exception) {
                PaymentResult.Error(e.message ?: "Unknown error")
            }
        }
    }

    suspend fun getTransactionHistory(userId: String): List<WalletTransaction> {
        return withContext(Dispatchers.IO) {
            try {
                val response = apiService.getTransactionHistory(userId)
                if (response.isSuccessful && response.body() != null) {
                    response.body()!!
                } else {
                    emptyList()
                }
            } catch (e: Exception) {
                emptyList()
            }
        }
    }

    private fun saveBalanceSecurely(balance: WalletBalance) {
        val balanceData = "${balance.balance}:${balance.currency}:${balance.availableBalance}"
        val encrypted = securityManager.encryptData(balanceData)
        securityManager.saveEncryptedData("wallet_balance", encrypted)
    }

    private fun saveTransactionSecurely(transaction: WalletTransaction) {
        val transactionData = "${transaction.transactionId}:${transaction.amount}:${transaction.currency}"
        val encrypted = securityManager.encryptData(transactionData)
        securityManager.saveEncryptedData("tx_${transaction.transactionId}", encrypted)
    }

    fun getCachedBalance(): WalletBalance? {
        return try {
            val encrypted = securityManager.getEncryptedData("wallet_balance")
            if (encrypted.isNotEmpty()) {
                val decrypted = securityManager.decryptData(encrypted)
                val parts = decrypted.split(":")
                WalletBalance(
                    balance = parts[0].toDouble(),
                    currency = parts[1],
                    availableBalance = parts[2].toDouble()
                )
            } else null
        } catch (e: Exception) {
            null
        }
    }
}

// PaymentProcessor.kt
import android.content.Context
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.coroutines.flow.flowOn

class PaymentProcessor(
    private val context: Context,
    private val apiService: PaymentApiService,
    private val securityManager: SecurityManager
) {

    suspend fun processPayment(
        userId: String,
        amount: Double,
        currency: String,
        paymentMethod: String,
        description: String,
        metadata: Map<String, String>? = null
    ): Flow<PaymentResult> = flow {
        emit(PaymentResult.Loading)
        
        try {
            if (!validatePaymentAmount(amount)) {
                emit(PaymentResult.Error("Invalid payment amount"))
                return@flow
            }

            val request = PaymentRequest(
                amount = amount,
                currency = currency,
                paymentMethod = paymentMethod,
                description = description,
                userId = userId,
                metadata = metadata
            )

            val response = apiService.processPayment(request)
            
            if (response.isSuccessful && response.body()?.success == true) {
                val paymentResponse = response.body()!!
                val transaction = WalletTransaction(
                    transactionId = paymentResponse.transactionId ?: "",
                    amount = amount,
                    currency = currency,
                    timestamp = System.currentTimeMillis(),
                    type = TransactionType.PURCHASE,
                    status = TransactionStatus.COMPLETED,
                    description = description
                )
                
                savePaymentRecordSecurely(transaction)
                emit(PaymentResult.Success(transaction))
            } else {
                emit(PaymentResult.Error(
                    response.body()?.message ?: "Payment processing failed",
                    response.body()?.errorCode
                ))
            }
        } catch (e: Exception) {
            emit(PaymentResult.Error(e.message ?: "Payment failed"))
        }
    }.flowOn(Dispatchers.IO)

    suspend fun addPaymentCard(
        userId: String,
        cardNumber: String,
        expiryMonth: Int,
        expiryYear: Int,
        cvv: String,
        cardholderName: String
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                if (!validateCard(cardNumber, expiryMonth, expiryYear, cvv)) {
                    return@withContext PaymentResult.Error("Invalid card details")
                }

                val encryptedCardNumber = securityManager.encryptData(cardNumber)
                val encryptedCvv = securityManager.encryptData(cvv)

                val cardData = mapOf(
                    "user_id" to userId,
                    "card_number" to encryptedCardNumber,
                    "expiry_month" to expiryMonth.toString(),
                    "expiry_year" to expiryYear.toString(),
                    "cvv" to encryptedCvv,
                    "cardholder_name" to cardholderName
                )

                val response = apiService.addPaymentCard(cardData)
                
                if (response.isSuccessful && response.body()?.success == true) {
                    PaymentResult.Success(
                        WalletTransaction(
                            transactionId = response.body()!!.transactionId ?: "",
                            amount = 0.0,
                            currency = "USD",
                            timestamp = System.currentTimeMillis(),
                            type = TransactionType.DEPOSIT,
                            status = TransactionStatus.COMPLETED,
                            description = "Card Added",
                            cardLastFour = cardNumber.takeLast(4)
                        )
                    )
                } else {
                    PaymentResult.Error(
                        response.body()?.message ?: "Failed to add card",
                        response.body()?.errorCode
                    )
                }
            } catch (e: Exception) {
                PaymentResult.Error(e.message ?: "Failed to add card")
            }
        }
    }

    suspend fun getPaymentCards(userId: String): List<PaymentCard> {
        return withContext(Dispatchers.IO) {
            try {
                val response = apiService.getPaymentCards(userId)
                if (response.isSuccessful && response.body() != null) {
                    response.body()!!
                } else {
                    emptyList()
                }
            } catch (e: Exception) {
                emptyList()
            }
        }
    }

    suspend fun removePaymentCard(cardId: String): Boolean {
        return withContext(Dispatchers.IO) {
            try {
                val response = apiService.removePaymentCard(cardId)
                response.isSuccessful && response.body()?.success == true
            } catch (e: Exception) {
                false
            }
        }
    }

    private fun validatePaymentAmount(amount: Double): Boolean {
        return amount > 0.0 && amount <= 999999.99
    }

    private fun validateCard(
        cardNumber: String,
        expiryMonth: Int,
        expiryYear: Int,
        cvv: String
    ): Boolean {
        if (cardNumber.length < 13 || cardNumber.length > 19) return false
        if (!cardNumber.all { it.isDigit() }) return false
        if (expiryMonth !in 1..12) return false
        if (expiryYear < 2024) return false
        if (cvv.length !in 3..4 || !cvv.all { it.isDigit() }) return false
        return luhnCheck(cardNumber)
    }

    private fun luhnCheck(cardNumber: String): Boolean {
        var sum = 0
        var alternate = false
        for (i in cardNumber.length - 1 downTo 0) {
            var n = cardNumber[i].toString().toInt()
            if (alternate) {
                n *= 2
                if (n > 9) n -= 9
            }
            sum += n
            alternate = !alternate
        }
        return sum % 10 == 0
    }

    private fun savePaymentRecordSecurely(transaction: WalletTransaction) {
        val paymentData = "${transaction.transactionId}:${transaction.amount}:${transaction.status}"
        val encrypted = securityManager.encryptData(paymentData)
        securityManager.saveEncryptedData("payment_${transaction.transactionId}", encrypted)
    }

    suspend fun verifyPayment(transactionId: String, verificationCode: String): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val verification = mapOf(
                    "transaction_id" to transactionId,
                    "verification_code" to verificationCode
                )
                
                val response = apiService.verifyPayment(verification)
                if (response.isSuccessful && response.body()?.success == true) {
                    PaymentResult.Success(
                        WalletTransaction(
                            transactionId = transactionId,
                            amount = 0.0,
                            currency = "USD",
                            timestamp = System.currentTimeMillis(),
                            type = TransactionType.PURCHASE,
                            status = TransactionStatus.COMPLETED,
                            description = "Payment Verified"
                        )
                    )
                } else {
                    PaymentResult.Error("Verification failed")
                }
            } catch (e: Exception) {
                PaymentResult.Error(e.message ?: "Verification failed")
            }
        }
    }
}

// PaymentModule.kt
import android.app.Activity
import android.content.Context

class PaymentModule private constructor(private val context: Context) {

    private val securityManager = SecurityManager(context)
    private val apiService = NetworkModule.providePaymentApiService()
    private val walletManager = WalletManager(apiService, securityManager)
    private val paymentProcessor = PaymentProcessor(context, apiService, securityManager)
    private val inAppPurchaseManager = InAppPurchaseManager(context, securityManager)

    fun getWalletManager(): WalletManager = walletManager
    fun getPaymentProcessor(): PaymentProcessor = paymentProcessor
    fun getInAppPurchaseManager(): InAppPurchaseManager = inAppPurchaseManager
    fun getSecurityManager(): SecurityManager = securityManager

    suspend fun processInAppPurchase(
        activity: Activity,
        productId: String,
        productType: String = "inapp"
    ): PaymentResult {
        val products = inAppPurchaseManager.queryProducts(listOf(productId), productType)
        return if (products.isNotEmpty()) {
            PaymentResult.Success(
                WalletTransaction(
                    transactionId = productId,
                    amount = products[0].priceMicros / 1_000_000.0,
                    currency = products[0].currency,
                    timestamp = System.currentTimeMillis(),
                    type = TransactionType.PURCHASE,
                    status = TransactionStatus.PENDING,
                    description = products[0].name
                )
            )
        } else {
            PaymentResult.Error("Product not found")
        }
    }

    fun clearAllData() {
        securityManager.clearAllData()
        inAppPurchaseManager.disconnect()
    }

    companion object {
        @Volatile
        private var INSTANCE: PaymentModule? = null

        fun getInstance(context: Context): PaymentModule {
            return INSTANCE ?: synchronized(this) {
                INSTANCE ?: PaymentModule(context.applicationContext).also { INSTANCE = it }
            }
        }
    }
}